export default {
  props: {
    size: {
      type: String,
    },
    theme: {
      type: String,
      default: "primary",
    },
    outlined: {
      type: Boolean,
      default: false,
    },
  },
  methods: {
    handleClick() {
      this.$emit("click");
    },
  },
  computed: {
    classes() {
      return [
        `btn--${this.theme}`,
        this.size && `btn--${this.size}`,
        this.outlined && `btn--outlined`,
      ];
    },
  },
};
