import Btn from '@/components/atoms/Btn.vue'
import Input from '@/components/atoms/Input.vue'
import Robot from '@/model/NeuralNetwork/Robot'
import ProgressBar from '../atoms/ProgressBar.vue'

const trainingProgress = {
  current: 0,
  diff: 0,
  updateThreshold: 0
}

export default {
  components: { Btn, Input, ProgressBar },
  name: 'RobotTrainingForm',
  props: {
    progressUpdateThreshold: {
      type: Number,
      default: 0.005,
    },
    haltTimeout: {
      type: Number,
      default: 10,
    },
  },
  data() {
    return {
      training: false,
      percent: 0,
      trainingPromise: null,
      form: {
        mutation: 0,
        generationCount: 0,
        populationSize: 0,
        useBias: false,
      },
    }
  },
  methods: {
    async trainRobot(evt) {
      evt.preventDefault()
      this.training = true
      this.percent = 0
      trainingProgress.updateThreshold =  this.progressUpdateThreshold / this.form.generationCount
      const trainingPromise = Robot.getTrained(
        [64,16],
        this.form.populationSize,
        this.form.generationCount,
        this.form.mutation,
        false,
        this.updateProgress,
        this.haltTimeout
      )

      trainingPromise
        .then((robot) => {
          this.$emit('trained', { robot })
        })
        .finally(() => {
          this.training = false
        })
    },
    updateProgress(data) {
      const progress = data.generation / data.generationCount
      trainingProgress.diff += progress - trainingProgress.current
      trainingProgress.current = progress
      if (trainingProgress.diff >= this.progressUpdateThreshold) {
        this.percent = trainingProgress.current
        trainingProgress.diff = 0
      }
    },
  },
}
