import Card from '../components/atoms/Card.vue'
import RobotTrainingForm from '../components/molecule/RobotTrainingForm.vue'
import Board from '../components/molecule/Board.vue'

export default {
  components: { Card, RobotTrainingForm, Board },
  data() {
    return {
      robot: null,
      training: false,
      percent: 0,
      elementPercent: 0,
      samples: [],
    }
  },
  methods: {
    handleTrainingUpdate(update) {
      this.robot = update.robot
      this.getSampleBoards()
    },
    getSampleBoards(count = 12) {
      this.samples = []
      for (let i = 0; i < count; i++) {
        this.samples.push({
          score: this.robot.play(),
          board: this.robot.board.clone(),
        })
      }
    },
  },
}
